CREATE DATABASE IF NOT EXISTS bookstore CHARACTER SET utf8 COLLATE utf8_general_ci;
USE bookstore;

CREATE TABLE IF NOT EXISTS books (
    id          INT AUTO_INCREMENT PRIMARY KEY,
    title       VARCHAR(200) NOT NULL,
    author      VARCHAR(150) NOT NULL,
    genre       VARCHAR(50)  NOT NULL DEFAULT 'Разное',
    year        SMALLINT     DEFAULT NULL,
    price       DECIMAL(8,2) NOT NULL DEFAULT 0,
    description TEXT,
    added_at    DATETIME     NOT NULL DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

CREATE TABLE IF NOT EXISTS cart (
    id        INT AUTO_INCREMENT PRIMARY KEY,
    book_id   INT NOT NULL,
    qty       INT NOT NULL DEFAULT 1,
    added_at  DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (book_id) REFERENCES books(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

INSERT INTO books (title, author, genre, year, price, description) VALUES
('Мастер и Маргарита', 'Булгаков М.А.', 'Роман', 1967, 450, 'Один из самых известных романов XX века. В Москву приезжает таинственный иностранец Воланд со своей свитой. Роман сочетает сатиру на советское общество с философской притчей о добре и зле, свободе и вере.'),
('Преступление и наказание', 'Достоевский Ф.М.', 'Роман', 1866, 520, 'Роман о студенте Раскольникове, который убивает старуху-процентщицу и её сестру. Глубокое исследование психологии преступника, вины и искупления.'),
('Война и мир', 'Толстой Л.Н.', 'Роман', 1869, 680, 'Эпопея, охватывающая период с 1805 по 1820 год. Судьбы нескольких дворянских семей на фоне наполеоновских войн и русского общества эпохи.'),
('Идиот', 'Достоевский Ф.М.', 'Роман', 1869, 490, 'История князя Мышкина — человека кристальной честности и доброты, — и его столкновения с жестоким и меркантильным миром.'),
('Анна Каренина', 'Толстой Л.Н.', 'Роман', 1877, 510, 'Трагическая история замужней женщины, полюбившей графа Вронского. Роман о любви, семье, обществе и личной свободе.'),

('1984', 'Оруэлл Дж.', 'Фантастика', 1949, 420, 'Антиутопия о тоталитарном государстве Океания, где Большой Брат следит за каждым. Роман о свободе мысли, пропаганде и сопротивлении системе.'),
('Дюна', 'Херберт Ф.', 'Фантастика', 1965, 550, 'Космическая эпопея о пустынной планете Арракис — единственном источнике ценнейшего вещества во Вселенной. История о политике, религии и экологии.'),
('Солярис', 'Лем С.', 'Фантастика', 1961, 380, 'Учёные на орбитальной станции над планетой Солярис сталкиваются с непостижимым явлением. Философский роман о границах человеческого познания.'),
('Марсианские хроники', 'Брэдбери Р.', 'Фантастика', 1950, 410, 'Цикл рассказов о колонизации Марса. Поэтическая и меланхоличная книга о природе человека, памяти и столкновении цивилизаций.'),
('Автостопом по галактике', 'Адамс Д.', 'Фантастика', 1979, 350, 'Комедийная фантастика о Земле, уничтоженной для строительства гиперпространственной магистрали. Ответ на главный вопрос жизни, вселенной и всего — 42.'),

('Убийство в «Восточном экспрессе»', 'Кристи А.', 'Детектив', 1934, 480, 'Эркюль Пуаро расследует убийство, совершённое в запертом купе поезда. Один из самых известных детективных романов с неожиданной развязкой.'),
('Собака Баскервилей', 'Конан Дойл А.', 'Детектив', 1902, 320, 'Шерлок Холмс расследует легенду о призрачной собаке, якобы преследующей род Баскервилей. Классика детективного жанра.'),
('Девушка с татуировкой дракона', 'Ларссон С.', 'Детектив', 2005, 470, 'Журналист и хакер расследуют многолетнее исчезновение девушки из богатой семьи. Скандинавский детектив с острой социальной критикой.'),
('Десять негритят', 'Кристи А.', 'Детектив', 1939, 390, 'Десять незнакомцев приглашены на уединённый остров. Один за другим они погибают. Убийца — один из них. Классический детектив-головоломка.'),
('Имя розы', 'Эко У.', 'Детектив', 1980, 590, 'Монах-францисканец расследует серию таинственных смертей в средневековом аббатстве. Детектив, пронизанный философией и семиотикой.'),

('Робинзон Крузо', 'Дефо Д.', 'Приключения', 1719, 280, 'История моряка, потерпевшего кораблекрушение и проведшего 28 лет на необитаемом острове. Один из первых романов в истории английской литературы.'),
('Граф Монте-Кристо', 'Дюма А.', 'Приключения', 1844, 460, 'Моряк Эдмон Дантес, несправедливо заключённый в тюрьму, бежит и обретает несметное богатство, чтобы отомстить своим врагам.'),
('Остров сокровищ', 'Стивенсон Р.Л.', 'Приключения', 1883, 310, 'Юный Джим Хокинс вместе с отважными спутниками отправляется на поиски пиратского клада. Классика приключенческой литературы для всех возрастов.'),
('Три мушкетёра', 'Дюма А.', 'Приключения', 1844, 440, 'Молодой гасконец д\'Артаньян приезжает в Париж и становится другом трёх королевских мушкетёров. Роман о дружбе, чести и приключениях.'),
('Капитан Фракасс', 'Готье Т.', 'Приключения', 1863, 360, 'Обедневший барон примыкает к труппе бродячих актёров под именем капитана Фракасса. Романтическое приключение во Франции XVII века.'),

('Краткая история времени', 'Хокинг С.', 'Наука', 1988, 540, 'Доступное изложение современной физики и космологии: Большой взрыв, чёрные дыры, природа времени. Стала мировым бестселлером, объясняя сложное простым языком.'),
('Sapiens', 'Харари Ю.Н.', 'Наука', 2011, 610, 'История человечества от появления Homo sapiens до наших дней. Автор анализирует, как биология, история и культура сформировали современный мир.'),
('Эгоистичный ген', 'Докинз Р.', 'Наука', 1976, 500, 'Революционный взгляд на эволюцию с точки зрения гена, а не организма. Книга ввела понятие «мем» и изменила понимание биологической эволюции.'),
('Происхождение видов', 'Дарвин Ч.', 'Наука', 1859, 380, 'Основополагающий труд, в котором Дарвин излагает теорию эволюции путём естественного отбора. Одна из самых влиятельных научных книг в истории.'),
('Физика невозможного', 'Каку М.', 'Наука', 2008, 530, 'Физик-теоретик исследует технологии, которые сегодня кажутся невозможными: телепортация, машина времени, силовые поля. Что из этого реально?');
